package com.yottastudios.ns.collabspace.workspace.controller;

import com.yottastudios.ns.collabspace.auth.vo.CreateNotifyVo;
import com.yottastudios.ns.collabspace.core.support.ResponseData;
import com.yottastudios.ns.collabspace.grpc.IApitableGrpcClientService;
import com.yottastudios.ns.collabspace.shared.component.scanner.annotation.ApiResource;
import com.yottastudios.ns.collabspace.shared.component.scanner.annotation.PostResource;
import com.yottastudios.ns.collabspace.workspace.ro.CreateExternalNotifyRo;
import io.swagger.v3.oas.annotations.Operation;
import io.swagger.v3.oas.annotations.tags.Tag;
import jakarta.annotation.Resource;
import jakarta.validation.Valid;
import lombok.extern.slf4j.Slf4j;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RestController;

@Slf4j
@RestController
@Tag(name = "Notification")
@ApiResource(path = "/notification")
public class NotificationController {

    @Resource
    private IApitableGrpcClientService apitableGrpcClientService;

    @PostResource(path = "/createExternalNotify", requiredPermission = false)
    @Operation(summary = "Create External Notify")
    public ResponseData<CreateNotifyVo> createExternalNotify(@RequestBody @Valid CreateExternalNotifyRo ro) {
        log.info("createExternalNotify: spaceId={}, templateId={}, sourceSystem={}",
                ro.getSpaceId(), ro.getTemplateId(), ro.getSourceSystem());
        CreateNotifyVo result = apitableGrpcClientService.createExternalNotify(
                ro.getToUserEmails(),
                ro.getSpaceId(),
                ro.getTemplateId(),
                ro.getFromUserEmail(),
                ro.getNotifyBody(),
                ro.getNodeId(),
                ro.getSourceSystem()
        );
        return ResponseData.success(result);
    }
}

